// Omise webhook payload: { key: 'charge.complete', data: { id, status, paid_at, ... } }
const body = $json.body || {};
const data = body.data || {};
let status = 'pending';
if (data.status === 'successful' || data.paid === true) status = 'paid';
else if (data.status === 'failed') status = 'failed';
else if (data.status === 'expired') status = 'expired';
return [{
  json: {
    charge_id: data.id || '',
    status,
    paid_at: data.paid_at || (status === 'paid' ? new Date().toISOString() : ''),
    raw: JSON.stringify(body).replace(/'/g, "''")
  }
}];
